external_knowledge:
Age Group 1: Under 18 years old;
Age Group 2: 18 to 30 years old;
Age Group 3: 31 to 50 years old;
Age Group 4: Over 50 years old;
The survival rate is calculated as the number of survivors divided by the total number of passengers in each group, multiplied by 100.

sql:
SELECT cabin_number, COUNT(*) as Total_Passengers
FROM cabin_allocations
GROUP BY cabin_number;

SELECT AVG(survival_rate) AS average_survival_rate
FROM survival_statistics
WHERE pclass = 1 AND age_group_id = 1;

SELECT embarked, survived, COUNT(*) AS total_passengers
FROM passengers
GROUP BY embarked, survived;

SELECT COUNT(DISTINCT voyage_id)
FROM voyages
WHERE voyage_route = 'Southampton-Cherbourg-Queenstown-New York';

SELECT captain_name, COUNT(voyage_id) AS voyage_count
FROM voyages
GROUP BY captain_name;

external_knowledge:
- 'older ladies' refers to females aged 35 or above;
- 'on their own' implies they do not have a surviving spouse also on the Titanic;
- 'similar age' refers to the spouse also being 35 or older.

sql:
SELECT p.passenger_id, pv.voyage_id
FROM passengers p
JOIN passenger_voyages pv ON p.passenger_id = pv.passenger_id;
